    pod := &corev1.Pod{}
    err := s.client.Get(context.Background(), client.ObjectKey{Namespace: namespace, Name: name}, pod)
    if apierrors.IsNotFound(err) {
        http.Error(w, "Pod not found", http.StatusNotFound)
        return
    }
    if err != nil {
        http.Error(w, "Failed to get pod information", http.StatusInternalServerError)
        s.log.Error(err, "Failed to retrieve pod")
        return
    }

    // Proceed with handling the status update.
    // ...
}
```

This change ensures that only status updates for existing pods are processed, preventing unauthorized access and maintaining data integrity.

